content.text:
:root {
  --sans: Inter, "SF Pro Text", "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --mono: ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, "DejaVu Sans Mono", monospace;

  --bg: #ffffff;
  --fg: #111827;
  --accent: #111827;
  --muted: #6b7280;
  --border: #e5e7eb;

  --pad: 1.5rem;
  --max-width: 42rem;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f0f;
    --fg: #e0e0e0;
    --accent: #4d9fff;
    --muted: #888;
    --border: #2a2a2a;
  }
}

*, *::before, *::after {
  box-sizing: border-box;
}

body {
  font-family: var(--sans);
  font-size: 0.95rem;
  line-height: 1.6;
  background: var(--bg);
  color: var(--fg);
  margin: 0;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
  text-underline-offset: 0.15em;
}

h1, h2, h3 {
  font-size: 1rem;
  font-weight: bold;
  margin: 0 0 1rem;
}

p, ul, ol {
  margin: 0 0 0.75rem;
}

ul, ol {
  padding-left: 1.5rem;
}

code {
  background: var(--border);
  padding: 0.1em 0.35em;
  border-radius: 2px;
}

strong {
  font-weight: bold;
}

.app-shell {
  display: flex;
  flex-direction: column;
  min-height: 100dvh;
  background: var(--bg);
}

.topbar {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  min-height: 3rem;
  padding: 0.5rem 1rem;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
  font-family: var(--sans);
}

.back-link {
  color: var(--muted);
  text-decoration: none;
  font-size: 1.1rem;
}

.page {
  padding: var(--pad);
  max-width: var(--max-width);
  margin: 0 auto;
}

.home-intro {
  color: var(--muted);
  margin-bottom: 1rem;
}

.home-links {
  list-style: none;
  padding-left: 0;
}

.home-links li + li {
  margin-top: 0.35rem;
}

.canvas-app {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  background: var(--bg);
}

.canvas-stage {
  flex: 1;
  overflow: hidden;
  position: relative;
}

.toolbar-button {
  background: none;
  border: 1px solid var(--border);
  color: var(--muted);
  font-family: var(--mono);
  font-size: 0.85rem;
  padding: 0.1rem 0.6rem;
  cursor: pointer;
}

.control-label {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  color: var(--fg);
}

---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}

const {
  title = 'incomplete.fun',
  description = 'A collection of fun, incomplete things.',
} = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="icon" href="/favicon.ico" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <title>{title}</title>
  </head>
  <body>
    <slot />
  </body>
</html>

---
import BaseLayout from './BaseLayout.astro';

interface Props {
  name: string;
  back?: boolean;
}

const { name, back = false } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title}>
  <div class="app-shell">
    <div class="topbar">
      {back && <a class="back-link" href="/" aria-label="Back to home">←</a>}
      <span><strong>{name}</strong></span>
    </div>
    <main class="page">
      <slot />
    </main>
  </div>
</BaseLayout>

---
import PageLayout from '../../layouts/PageLayout.astro';

function fib(n: number): bigint {
  let a = 0n, b = 1n;
  for (let i = 0; i < n; i++) [a, b] = [b, a + b];
  return a;
}

const nParam = Astro.params.n ?? '';

if (!/^\d+$/.test(nParam)) {
  return new Response(null, { status: 404 });
}

const n = Number.parseInt(nParam, 10);
---

<PageLayout name="fibonacci" back>
  <p>fib({n}) = <strong>{fib(n).toString()}</strong></p>
</PageLayout>

